# ppdsp_results.py

import os
import glob
import re
import pandas as pd

def parse_logs():
    # Looking for .out files generated by the solvers
    log_files = glob.glob("ppdsp_*.out")
    
    results = []

    for file_path in log_files:
        filename = os.path.basename(file_path)
        
        # Extract metadata from filename (e.g., ppdsp_P-n22-k8_r35v8k3_cpsat.out)
        match = re.search(r"ppdsp_(.+)_r(\d+)v(\d+)k(\d+)_(.+)\.out", filename)
        if not match:
            continue
            
        instance = match.group(1)
        reqs = int(match.group(2))
        vehicles = int(match.group(3))
        method = match.group(5) # e.g., cpsat, maxsat, hybrid_bc, full_bc
        
        obj = None
        runtime = None

        with open(file_path, "r", encoding="utf-8") as f:
            content = f.read()
            
            # --- Objective Parsing ---
            # CP-SAT format
            if method == "cpsat":
                obj_match = re.search(r"\[CP-SAT\] FINAL OBJ:\s*(-?\d+\.?\d*)", content)
                if obj_match:
                    obj = float(obj_match.group(1))
            # MaxSAT format (UWrMaxSAT)
            elif method == "maxsat":
                obj_match = re.search(r"\[UWrMaxSAT\] OBJ:\s*(-?\d+\.?\d*)", content)
                if obj_match:
                    obj = float(obj_match.group(1))
            # MIP format (Gurobi)
            elif "bc" in method:
                obj_match = re.search(r"\[Gurobi\] BEST OBJ:\s*(-?\d+\.?\d*)", content)
                if obj_match:
                    obj = float(obj_match.group(1))

            # --- Runtime Parsing ---
            if method == "cpsat":
                time_match = re.search(r"\[CP-SAT\] Total Runtime:\s*(\d+\.\d+)", content)
                if time_match:
                    runtime = float(time_match.group(1))
            elif method == "maxsat":
                # MaxSAT records CPU time inside the solver output
                time_match = re.search(r"c CPU time\s*:\s*(\d+\.\d+)\s*s", content)
                if time_match:
                    runtime = float(time_match.group(1))
            elif "bc" in method:
                time_match = re.search(r"\[Gurobi\] Runtime:\s*(\d+\.\d+)", content)
                if time_match:
                    runtime = float(time_match.group(1))

        # Default fallback if a run completely failed/timeout without yielding a time string
        if runtime is None:
            runtime = 3600.0

        results.append({
            "Instance": instance,
            "Requests": reqs,
            "Vehicles": vehicles,
            "Method": method,
            "Objective(NetProfit)": obj,
            "Time(s)": runtime
        })

    if not results:
        print("[Warning] No log files parsed. Make sure .out files exist in the directory.")
        return

    # Convert results to Pandas DataFrame
    df = pd.DataFrame(results)
    
    # Sort results for cleaner CSV layout
    df = df.sort_values(by=["Instance", "Requests", "Method"])

    # Export to CSV using Pandas
    output_csv = "ppdsp_results.csv"
    df.to_csv(output_csv, index=False, encoding="utf-8")

    print(f"\n[Success] PPDSP results compiled into {output_csv}. Total runs parsed: {len(df)}")

if __name__ == "__main__":
    parse_logs()